// ═══════════════════════════════════════════════════════════════
// ID resolution — map provider ids from FALLBACK_PROFILES onto
// the logo ids used as keys in LOGOS.
// ═══════════════════════════════════════════════════════════════

// Aliases for provider ids that don't directly match a logo id.
const ID_ALIASES: Record<string, string> = {
  "fireworks": "fireworks-ai",
  "moonshot": "moonshotai",
  "ionet": "io-net",
  "ollama": "ollama-cloud",
  "llamacpp": "llama",
  "azure-openai": "azure",
  "azure-cognitive-services": "azure",
  "gitlab-duo": "gitlab",
  "cloudflare-ai-gateway": "cloudflare-workers-ai",
  "vercel-ai-gateway": "vercel",
};

/** Resolve a provider id to a logo id (key into LOGOS). */
function resolveLogoId(providerId: string): string | undefined {
  const id = providerId.toLowerCase();
  if (ID_ALIASES[id]) return ID_ALIASES[id];
  if (LOGOS[id]) return id;
  return undefined;
}

// ═══════════════════════════════════════════════════════════════
// Component
// ═══════════════════════════════════════════════════════════════

export interface ProviderLogoProps {
  /** Provider id from FALLBACK_PROFILES (e.g. 'openai', 'azure-openai'). */
  providerId: string;
  /** Optional display name used for the fallback letter avatar. */
  name?: string;
  /** Pixel size of the rendered logo (square). Default 16. */
  size?: number;
  /** Optional className for the wrapper. */
  className?: string;
  /** Optional inline style for the wrapper. */
  style?: React.CSSProperties;
}

/**
 * Renders a provider's logo as an inline SVG, inheriting currentColor.
 * Falls back to a first-letter avatar (square + letter) when no logo is
 * available for the given provider id.
 */
export const ProviderLogo: React.FC<ProviderLogoProps> = ({
  providerId,
  name,
  size = 16,
  className,
  style,
}) => {
  const logoId = resolveLogoId(providerId);
  const logo = logoId ? LOGOS[logoId] : undefined;

  if (logo) {
    return (
      <svg
        className={className}
        style={{ width: size, height: size, flexShrink: 0, ...style }}
        viewBox={logo.viewBox}
        fill="currentColor"
        aria-hidden="true"
        focusable="false"
      >
        {logo.paths.map((d, i) => (
          <path key={i} d={d} />
        ))}
      </svg>
    );
  }

  // Fallback: first-letter avatar.
  const letter = (name || providerId).trim().charAt(0).toUpperCase() || '?';
  const fontSize = Math.max(9, Math.round(size * 0.6));
  return (
    <span
      className={className}
      style={{
        display: 'inline-flex',
        alignItems: 'center',
        justifyContent: 'center',
        width: size,
        height: size,
        borderRadius: Math.max(2, Math.round(size * 0.2)),
        background: 'var(--bg-overlay-l1)',
        color: 'var(--text-secondary)',
        fontSize,
        fontWeight: 600,
        lineHeight: 1,
        flexShrink: 0,
        userSelect: 'none',
        ...style,
      }}
      aria-hidden="true"
    >
      {letter}
    </span>
  );
};

export default ProviderLogo;
